public class DailyRateCreationBatch implements Database.Batchable<SObject> {

    public String query;

    public DailyRateCreationBatch(String q) {
        this.query = q;
    }

    public Database.QueryLocator start(Database.BatchableContext bc) {
        return Database.getQueryLocator(query);
    }

    public void execute(Database.BatchableContext bc, List<SObject> scope) {
        List<Contact> contacts = (List<Contact>) scope;
        List<Daily_Rate__c> rates = new List<Daily_Rate__c>();
        for (Contact c : contacts) {
            Daily_Rate__c rate = new Daily_Rate__c();
            rate.Contact__c = c.Id;
            rate.Date__c = Date.today();
            rate.Rate__c = Math.random() * 10;
            rates.add(rate);
        }
        Database.insert(rates, false);
    }

    public void finish(Database.BatchableContext bc) {
    }
}

String soql = 'SELECT Id, Name FROM Contact';
DailyRateCreationBatch job = new DailyRateCreationBatch(soql);
Id batchId = Database.executeBatch(job, 10);
System.debug('Batch started: ' + batchId);

